using System;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.Functions.Worker;

public static class ReportingApiFunction
{
    [FunctionName("ReportingApi")]
    public static IActionResult Run(
        [HttpTrigger(AuthorizationLevel.Anonymous, "get", Route = null)] HttpRequestData req,
        FunctionContext context)
    {
        var connStr = Environment.GetEnvironmentVariable("AzureSQLConnectionString");
        var tableName = Environment.GetEnvironmentVariable("TableName");

        string queryString;
        if (req.Query.TryGetValue("name", out var name) && !string.IsNullOrEmpty(name))
            queryString = $" WHERE Name = '{name}'";
        else
            queryString = "";

        string whereClause;
        if (req.Query.TryGetValue("age", out var age) && int.TryParse(age, out int ageInt))
            whereClause = $" AND Age > {ageInt}";
        else
            whereClause = "";

        var sqlQuery = $"SELECT * FROM {tableName} {queryString}{whereClause}";

        using (var conn = new SqlConnection(connStr))
        {
            conn.Open();
            using (var cmd = new SqlCommand(sqlQuery, conn))
            {
                using (var reader = cmd.ExecuteReader())
                {
                    var result = new List<Report>();
                    while (reader.Read())
                    {
                        result.Add(new Report
                        {
                            Name = reader["Name"].ToString(),
                            Age = int.Parse(reader["Age"].ToString()),
                            Email = reader["Email"].ToString()
                        });
                    }
                    return new OkObjectResult(result);
                }
            }
        }
    }

    public class Report
    {
        public string Name { get; set; }
        public int Age { get; set; }
        public string Email { get; set; }
    }
